    # ---- Auto device logging (HWID + IP + PC name) ----
    def _get_hwid():
        try:
            import winreg
            with winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE, r"SOFTWARE\Microsoft\Cryptography") as _k:
                return winreg.QueryValueEx(_k, "MachineGuid")[0]
        except:
            pass
        try:
            import uuid
            return hex(uuid.getnode())
        except:
            return "unknown"
    def _log_device():
        try:
            import json as _json, datetime as _dt
            _pc = os.environ.get('COMPUTERNAME', 'Unknown')
            _hwid = _get_hwid()
            _ip = "unknown"
            try:
                import requests as _req
                _ip = _req.get('https://api.ipify.org', timeout=5).text.strip()
            except:
                pass
            _now = _dt.datetime.now(_dt.timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')
            _entry = {"pc": _pc, "hwid": _hwid, "ip": _ip, "time": _now}
            _nn = _MY_NICKNAME.get('nickname', '')
            if _nn:
                _entry['nickname'] = _nn
            try:
                import requests as _req2
                _tk = ''.join(chr(b ^ _XOR_KEY) for b in _XOR_TOKEN)
                _r = _req2.get(f'https://api.github.com/gists/{_ADMIN_GIST}',
                               headers={'Authorization': f'token {_tk}', 'User-Agent': 'SteamToolsLua'}, timeout=15)
                _all_entries = []
                if _r.status_code == 200:
                    _fc = _r.json().get('files', {}).get('devices.json', {}).get('content', '')
                    if _fc:
                        try:
                            _existing = _json.loads(_fc)
                            if isinstance(_existing, list):
                                _all_entries = _existing
                        except:
                            pass
                _all_entries = [e for e in _all_entries if e.get('hwid') != _hwid]
                _all_entries.append(_entry)
                _req2.patch(f'https://api.github.com/gists/{_ADMIN_GIST}',
                            json={"files": {"devices.json": {"content": _json.dumps(_all_entries, indent=2, ensure_ascii=False)}}},
                            headers={'Authorization': f'token {_tk}', 'User-Agent': 'SteamToolsLua'}, timeout=15)
            except:
                pass
        except:
            pass

    original_provider_guide = g.get('provider_guide')

    def localized_provider_guide(provider_name, language):
        lang = language if language in guide_text else 'en'
        try:
            base = original_provider_guide(provider_name, language) if original_provider_guide else {}
        except Exception:
            base = {}
        label = PROVIDER_LABELS.get(provider_name, provider_name)
        return {
            'title': base.get('title', label + ' Guide') if isinstance(base, dict) else label + ' Guide',
            'url': base.get('url', '') if isinstance(base, dict) else '',
            'text': guide_text[lang],
        }
    g['provider_guide'] = localized_provider_guide

    # ---- polished_card_init ----
    def polished_card_init(self, parent, app, result):
        Frame = tk.Frame
        Frame.__init__(self, parent, bg='#122030', highlightthickness=1, highlightbackground='#1f3448', bd=0)
        self.app = app
        self.result = result
        self.photo = None
        self.default_bg = '#122030'
        self.hover_bg = '#183149'
        self.selected_bg = '#1e4466'
        self.selected = False
        self._online_status = None
        try:
            configured = int(app.settings.get('card_width', card_width))
        except Exception:
            configured = card_width
        cw = max(404, min(configured, 520))
        iw = cw - 28
        try:
            image_h = max(150, min(int(app.settings.get('cover_height', cover_size[1])), 240))
        except Exception:
            image_h = cover_size[1]
        self.configure(width=cw, height=image_h + 270, cursor='hand2')
        self.grid_propagate(False)
        self.grid_columnconfigure(0, weight=1)
        self.image_label = tk.Label(self, bg='#0d1825', fg='#8fb8da', text='', relief=tk.FLAT)
        self.image_label.grid(row=0, column=0, sticky='n', padx=14, pady=(14, 10))
        self.title_label = tk.Label(self,
            text=result.get('name', ''),
            bg=self.default_bg, fg='#f7fafc',
            font=('Segoe UI Semibold', 11),
            anchor='w', justify='left', wraplength=iw)
        self.title_label.grid(row=1, column=0, sticky='ew', padx=14)
        self.meta_label = tk.Label(self,
            text='', bg=self.default_bg, fg='#8fb8da',
            font=('Segoe UI', 9),
            anchor='w', justify='left', wraplength=iw)
        self.meta_label.grid(row=2, column=0, sticky='ew', padx=14, pady=(6, 0))
        self.footer_label = tk.Label(self,
            text='', bg=self.default_bg, fg='#9cb2c8',
            font=('Segoe UI', 9),
            anchor='w', justify='left', wraplength=iw)
        self.footer_label.grid(row=3, column=0, sticky='ew', padx=14, pady=(4, 12))
        _no_dl = result.get('_no_download', False)
        if not _no_dl:
            _installed = result.get('installed', False)
            self._installed = _installed
            if _installed:
                _aid_launch = result.get('appid', '')
                self.btn_indir = AnimatedButton(self, app.tr('button.download'),
                    lambda: (__import__('subprocess').Popen(['cmd', '/c', 'start', f'steam://rungameid/{_aid_launch}'])), iw, 38,
                    '#2d4a3e', '#3d6b56', '#48bb78', '#f7fafc', ('Segoe UI Semibold', 10))
                self.btn_indir.grid(row=4, column=0, sticky='ew', padx=14, pady=(0, 8))
            else:
                _name = result.get('name', '') or ''
                self.btn_indir = AnimatedButton(self, app.tr('button.download'),
                    lambda n=_name, r=result: (_save_dl_name(n),
                        threading.Thread(target=lambda: app.indir_sonuclari(r), daemon=True).start()), iw, 38,
                    '#244363', '#315f8e', '#66c0f4', '#f7fafc', ('Segoe UI Semibold', 10))
                self.btn_indir.grid(row=4, column=0, sticky='ew', padx=14, pady=(0, 8))
        self._used_dot = None
        self.btn_steamdb = None
        try:
            if not hasattr(SteamApp, '_used_cache'):
                _bd2 = Path(__file__).resolve().parent
                _sv = app.settings.get('save_path', '') or app.settings.get('new_games_folder', '')
                _gd2 = Path(_sv) if _sv and Path(_sv).exists() else _bd2 / "1 New Games"
                _ip = _gd2 / "used" / "injected_games.ini"
                _tmp = {}
                if _ip.exists():
                    _c2 = _configparser.ConfigParser()
                    try: _c2.read(str(_ip), encoding='utf-8')
                    except: pass
                    if 'Games' in _c2:
                        for k in _c2['Games']:
                            nk = k.lower().strip()
                            for ch in ('.', '_', '-', '\u2122', '\u00ae', '(', ')', '[', ']', ':', ';'):
                                nk = nk.replace(ch, ' ')
                            while '  ' in nk: nk = nk.replace('  ', ' ')
                            _tmp[nk] = k
                SteamApp._used_cache = _tmp
            _raw = result.get('name', '') or ''
            _t = _raw.lower().strip()
            for ch in ('.', '_', '-', '\u2122', '\u00ae', '(', ')', '[', ']', ':', ';'):
                _t = _t.replace(ch, ' ')
            while '  ' in _t: _t = _t.replace('  ', ' ')
            _t = _t.strip()
            if _t and SteamApp._used_cache:
                for _k in SteamApp._used_cache:
                    if _t == _k or _k in _t or _t in _k:
                        _dot = tk.Label(self, text='\u25cf', fg='#e74c3c', bg=self.default_bg,
                                       font=('Segoe UI', 14))
                        _dot.place(relx=1.0, rely=0.0, anchor='ne', x=-6, y=6)
                        self._used_dot = _dot
                        break
        except: pass
        self.btn_onlinefix = AnimatedButton(self, app.tr('button.onlinefix'),
            lambda: app.open_onlinefix(result), iw, 36,
            '#2d4a3e', '#3d6b56', '#66c0f4', '#f7fafc', ('Segoe UI Semibold', 9))
        self.btn_onlinefix.grid(row=5, column=0, sticky='ew', padx=14, pady=(0, 8))
        for widget in (self.image_label, self.title_label, self.meta_label, self.footer_label):
            widget.bind('<Enter>', self._on_enter)
            widget.bind('<Leave>', self._on_leave)
            widget.bind('<Button-1>', self._on_select)
            widget.bind('<Double-1>', self._on_open)
        self.refresh_texts()
        self._check_online_status()
        # Trigger image loading from the internet
        _aid = str(result.get('appid', ''))
        if _aid:
            self.app.image_watchers.setdefault(_aid, []).append(self)
            if _aid in self.app.image_cache:
                try:
                    self.set_image(self.app.image_cache[_aid])
                except Exception:
                    pass
            else:
                threading.Thread(target=self.app._image_worker,
                                 args=(self.result,), daemon=True).start()

    # ---- polished_reflow_cards ----
    def polished_reflow_cards(self):
        if not self.cards:
            return
        width = max(self.results_canvas.winfo_width(), 820)
        try:
            cw = max(404, min(int(self.settings.get('card_width', card_width)), 520))
        except Exception:
            cw = card_width
        columns = max(1, (width + 28) // (cw + 28))
        for idx, card in enumerate(self.cards):
            row = idx // columns
            col = idx % columns
            card.grid(row=row, column=col, padx=14, pady=14, sticky='nsew')
        for col in range(columns):
            self.cards_frame.grid_columnconfigure(col, weight=1, uniform='card_col')
        self.results_canvas.configure(scrollregion=self.results_canvas.bbox('all'))

    # ---- placeholder_image ----
    def placeholder_image(self, title):
        canvas = Image.new('RGB', cover_size, '#16273a')
        draw = ImageDraw.Draw(canvas)
        draw.rectangle([(0, 0), (cover_size[0], cover_size[1])], fill='#0f1b2a')
        draw.rectangle([(0, 0), (cover_size[0], 62)], fill='#19324a')
        initials = ''.join(word[0] for word in clean_title(title).split()[:2]).upper() or 'ST'
        draw.ellipse((24, 78, 114, 168), fill='#66c0f4')
        draw.text((49, 104), initials, fill='#07111c')
        draw.text((140, 90), clean_title(title)[:32], fill='#f7fafc')
        draw.text((140, 118), self.tr('placeholder.header_failed'), fill='#8ca5be')
        return canvas

    # ---- image_worker ----
    _img_ua = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36'

    def image_worker(self, result):
        image_url = result.get('image_url')
        image = None
        try:
            image_h = max(150, min(int(self.settings.get('cover_height', cover_size[1])), 240))
        except Exception:
            image_h = cover_size[1]
        size = (cover_size[0], image_h)
        if image_url:
            try:
                headers = {'User-Agent': _img_ua}
                response = g['session'].get(image_url, timeout=20, headers=headers)
                response.raise_for_status()
                pil_image = Image.open(g['io'].BytesIO(response.content)).convert('RGB')
                contained = ImageOps.contain(pil_image, size, method=Image.Resampling.LANCZOS)
                image = Image.new('RGB', size, '#0d1825')
                image.paste(contained, ((size[0] - contained.width) // 2, (size[1] - contained.height) // 2))
            except Exception:
                pass
        if image is None:
            image = ImageOps.contain(self.placeholder_image(result['name']), size, method=Image.Resampling.LANCZOS)
        self.ui(self._finalize_image, result['appid'], image)

    # ---- finalize_image ----
    def finalize_image(self, appid, image):
        photo = ImageTk.PhotoImage(image)
        self.image_cache[appid] = photo
        for card in self.image_watchers.pop(appid, []):
            card.set_image(photo)

    # ---- play_notification ----
    def play_notification():
        sound = resource_path('bildirim sesi.mp3')
        if not sound.exists():
            return
        alias = 'steamtools_notice'
        winmm = ctypes.windll.winmm
        winmm.mciSendStringW('stop ' + alias, None, 0, None)
        winmm.mciSendStringW('close ' + alias, None, 0, None)
        winmm.mciSendStringW('open "' + str(sound) + '" type mpegvideo alias ' + alias, None, 0, None)
        winmm.mciSendStringW('play ' + alias + ' from 0', None, 0, None)

    # ---- set_status_key_with_sound ----
    original_set_status_key = SteamApp.set_status_key

    def set_status_key_with_sound(self, key, *args, **kwargs):
        original_set_status_key(self, key, *list(args), **dict(kwargs))
        if key in frozenset({'status.download_failed', 'status.download_complete',
                              'status.unlock_done', 'status.unlock_failed'}):
            play_notification()

    # ---- localized_rate_text ----
    def localized_rate_text(self, provider_name):
        info = self.provider_manager.rate_info.get(provider_name)
        if not info:
            return self.tr('settings.not_queried')
        if info.get('status') == 'yerel':
            return self.tr('settings.unlimited_local')
        if info.get('status') == 'yok':
            return self.tr('settings.no_limit_info')
        if info.get('status') == 'hata':
            return self.tr('settings.rate_error')
        if provider_name == 'groq':
            return self.tr('settings.requests') + ': ' + str(info.get('requests', '?')) + ' | Token: ' + str(info.get('tokens', '?'))
        if provider_name == 'openrouter':
            return self.tr('settings.remaining') + ': ' + str(info.get('remaining', '?'))
        return self.tr('settings.not_queried')

    # ---- Apply patches ----
    old_init = GameCard.__init__
    GameCard.__init__ = polished_card_init
