    def _patched_refresh(self):
        source_key = self.result.get('source_key')
        if source_key:
            source_text = self.app.tr(source_key)
        else:
            source_text = self.result.get('source', '')
        footer_key = 'footer.free' if self.result.get('is_free') else 'footer.verified'
        self.meta_label.configure(text=f"App ID: {str(self.result.get('appid', ''))}  |  {source_text}")
        self.footer_label.configure(text=self.app.tr(footer_key))
        self.btn_indir.set_text(self.app.tr('button.download'))
        self.btn_onlinefix.set_text(self.app.tr('button.onlinefix'))
        self.set_busy(False)
    GameCard.refresh_texts = _patched_refresh
    _orig_set_busy = GameCard.set_busy
    def _patched_set_busy(self, value):
        global_busy = bool(getattr(self.app, 'busy', False))
        self.btn_indir.set_enabled(not global_busy)
        self.btn_onlinefix.set_enabled(not global_busy)
    GameCard.set_busy = _patched_set_busy
    _orig_on_open = GameCard._on_open
    def _patched_on_open(self, event):
        self.app.open_onlinefix(self.result)
    GameCard._on_open = _patched_on_open

    # ---- Status Indicator Helper ----
    def _set_indicator(self, text, state):
        try:
            if not hasattr(self, '_indicator_history'):
                self._indicator_history = []
            ts = _time.strftime('%H:%M:%S')
            self._indicator_history.append((ts, text, state))
            if len(self._indicator_history) > 50:
                self._indicator_history.pop(0)
            if hasattr(self, 'set_status'):
                self.set_status(text, state)
            else:
                colors = {'idle':'#708090','working':'#f6ad55','online':'#48bb78','offline':'#f56565'}
                labels = {'idle':'Beklemede/Idle','working':'Calisiyor/Working','online':'Aktif/Online','offline':'Hata/Error'}
                if hasattr(self, 'status_dot') and hasattr(self, 'status_oval'):
                    self.status_dot.itemconfig(self.status_oval, fill=colors.get(state, colors['idle']))
                    try:
                        self.status_dot.itemconfig(self.status_oval, tooltip=f'{labels.get(state, state)}: {text[:50]}')
                    except: pass
                if hasattr(self, 'status_var'):
                    self.status_var.set(f'{labels.get(state, state)}: {text[:60]}')
                if hasattr(self, 'status_lbl') and self.status_lbl.winfo_exists():
                    self.status_lbl.config(text='')
        except Exception:
            pass

    SteamApp._set_indicator = _set_indicator

    # ---- Headless PowerShell Runner ----
    import os as _os
    import shutil as _shutil
    import subprocess as _subprocess
    import tempfile as _tempfile
    import zipfile as _zipfile
    import configparser as _configparser
    import tkinter.messagebox as _messagebox
    import time as _time
    _batch_threading = threading

    # ---- Sound effects (disabled) ----
    def _play_sound(kind):
        pass

    def _run_headless_powershell(self, cmd, label, status_light=None):
        def _task():
            try:
                self.log(f"[{label}] başlatılıyor...")
                self._set_indicator(f"{label} {_tr(self, 'indicator.working')}", 'working')
                if status_light is not None:
                    try: status_light.config(fg='#f6ad55')
                    except: pass
                si = _subprocess.STARTUPINFO()
                si.dwFlags |= _subprocess.STARTF_USESHOWWINDOW
                result = _subprocess.run(
                    ["powershell", "-Command", cmd],
                    capture_output=True, text=True, timeout=300,
                    startupinfo=si, creationflags=0x08000000
                )
                if result.returncode == 0:
                    msg = f"{label} başarıyla tamamlandı."
                    self.log(f"[{label}] {msg}")
                    self._set_indicator(msg, 'online')
                    _play_sound('done')
                    if status_light is not None:
                        try: status_light.config(fg='#48bb78')
                        except: pass
                    # Post-install: move ltsteamplugin-main up one level
                    if 'luatools' in label.lower():
                        try:
                            _plugins = Path("C:\\Program Files (x86)\\Steam\\millennium\\plugins")
                            _luatools_dir = _plugins / "luatools"
                            if _luatools_dir.exists():
                                _subs = [d for d in _luatools_dir.iterdir() if d.is_dir()]
                                if _subs:
                                    _src = _subs[0]
                                    _dst = _plugins / _src.name
                                    if not _dst.exists():
                                        _shutil.move(str(_src), str(_dst))
                                        self.log(f"{_src.name} başarıyla plugins/ klasörüne taşındı.")
                        except Exception as e:
                            self.log(f"luatools klasör taşıma hatası: {e}")
                else:
                    err = result.stderr.strip()[:200] or "Bilinmeyen hata"
                    self.log(f"[{label}] HATA: {err}")
                    self._set_indicator(f"{label} {_tr(self, 'indicator.fail')}", 'offline')
                    _play_sound('error')
                    if status_light is not None:
                        try: status_light.config(fg='#f56565')
                        except: pass
            except _subprocess.TimeoutExpired:
                self.log(f"[{label}] zaman aşımı!")
                self._set_indicator(f"{label} {_tr(self, 'indicator.timeout')}", 'offline')
                _play_sound('error')
                if status_light is not None:
                    try: status_light.config(fg='#f56565')
                    except: pass
            except Exception as e:
                self.log(f"[{label}] HATA: {e}")
                self._set_indicator(f"{label} {_tr(self, 'indicator.err')}", 'offline')
                _play_sound('error')
                if status_light is not None:
                    try: status_light.config(fg='#f56565')
                    except: pass
        _batch_threading.Thread(target=_task, daemon=True).start()
        _play_sound('start')

    SteamApp._run_headless_powershell = _run_headless_powershell

    # ---- Batch Inject All ----
    def batch_inject_all(self):
        base_dir = Path(__file__).resolve().parent
        saved = self.settings.get('save_path', '') or self.settings.get('new_games_folder', '')
        if saved and Path(saved).exists():
            games_dir = Path(saved)
        else:
            games_dir = base_dir / "1 New Games"
        if not games_dir.exists():
            try:
                games_dir.mkdir(parents=True, exist_ok=True)
                self.log(f"[1 New Games] klasörü oluşturuldu: {games_dir}")
            except Exception as e:
                self.log(f"[1 New Games] klasörü oluşturulamadı: {e}")
                _messagebox.showerror(_tr(self, 'inject.err_title'), f"{_tr(self, 'inject.err_create')}\n{e}")
                return
        self.settings['new_games_folder'] = str(games_dir.resolve())
        g['save_settings'](self.settings)
        self.log(f"Taranan klasör: {games_dir}")
        self._set_indicator(_tr(self, 'indicator.scanning'), 'working')
        zips = sorted(games_dir.glob("*.zip"))
        if not zips:
            self.log(f"[{games_dir.name}] içinde .zip dosyası bulunamadı.")
            self._set_indicator(_tr(self, 'indicator.no_zips'), 'idle')
            _messagebox.showinfo(_tr(self, 'inject.info_title'), _tr(self, 'inject.no_zips_msg'))
            return
        # Show selection overlay inside main window
        _parent = getattr(self, 'results_canvas', None) or getattr(self, 'cards_frame', None) or self.root
        _sel_vars = {}
        _ov = tk.Frame(self.root, bg='#08080e', highlightthickness=1, highlightbackground='#1a1a30')
        _ov.place(x=0, y=0, relwidth=1, relheight=1, anchor='nw')
        _ov.lift()
        _top = tk.Frame(_ov, bg='#08080e')
        _top.pack(fill=tk.X, padx=16, pady=(14, 6))
        tk.Label(_top, text=_tr(self, 'inject.select_title'), font=('Bahnschrift SemiBold', 18),
                 fg='#e0e0f0', bg='#08080e').pack(side=tk.LEFT)
        _sel_all = tk.BooleanVar(value=True)
        def _toggle_all():
            v = _sel_all.get()
            for var in _sel_vars.values(): var.set(v)
        tk.Checkbutton(_top, text=_tr(self, 'inject.select_all'), variable=_sel_all,
                       command=_toggle_all, bg='#08080e', activebackground='#12122a',
                       selectcolor='#7c6fff', fg='#c0c0e0', font=('Segoe UI', 10)).pack(side=tk.RIGHT, padx=4)
        _sep = tk.Frame(_ov, bg='#1a1a30', height=1)
        _sep.pack(fill=tk.X, padx=16)
        _cf = tk.Frame(_ov, bg='#0a0a16')
        _cf.pack(fill=tk.BOTH, expand=True, padx=16, pady=(8, 10))
        _canv = tk.Canvas(_cf, bg='#0a0a16', highlightthickness=0)
        _scr = ttk.Scrollbar(_cf, orient=tk.VERTICAL, command=_canv.yview)
        _inner = tk.Frame(_canv, bg='#0a0a16')
        _inner.bind('<Configure>', lambda e: _canv.configure(scrollregion=_canv.bbox('all')))
        _canv.create_window((0, 0), window=_inner, anchor='nw')
        _canv.configure(yscrollcommand=_scr.set)
        _canv.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        _scr.pack(side=tk.RIGHT, fill=tk.Y)
        def _mw(e): _canv.yview('scroll', -e.delta//30, 'units')
        _canv.bind('<MouseWheel>', _mw)
        for i, zp in enumerate(zips):
            var = tk.BooleanVar(value=True)
            _sel_vars[zp] = var
            nm = zp.stem.replace('_', ' ').replace('-', ' ').strip()
            nm = ' '.join(w.capitalize() for w in nm.split())
            bg = '#0c0c20' if i % 2 == 0 else '#0a0a16'
            row = tk.Frame(_inner, bg=bg)
            row.pack(fill=tk.X, padx=6, pady=1)
            tk.Checkbutton(row, variable=var, bg=bg, activebackground='#14142a', selectcolor='#7c6fff',
                           fg='#d0d0e8', font=('Segoe UI', 10)).pack(side=tk.LEFT)
            tk.Label(row, text=nm, bg=bg, fg='#d0d0e8', font=('Segoe UI', 10), anchor='w').pack(side=tk.LEFT, fill=tk.X, expand=True)
            tk.Label(row, text=zp.name, bg=bg, fg='#686880', font=('Segoe UI', 8), anchor='e').pack(side=tk.RIGHT, padx=4)
        _btnf = tk.Frame(_ov, bg='#08080e')
        _btnf.pack(fill=tk.X, padx=16, pady=(0, 14))
        _ok = [False]
        def _confirm():
            _ok[0] = True; _ov.destroy()
        def _cancel():
            _ov.destroy()
        AB = g.get('AnimatedButton', AnimatedButton)
        AB(_btnf, _tr(self, 'inject.select_inject'), _confirm, 140, 34,
           '#1c1c3a', '#2a2a5a', '#7c6fff', '#e0e0f0',
           ('Segoe UI Semibold', 10)).pack(side=tk.RIGHT, padx=(8, 0))
        AB(_btnf, _tr(self, 'button.close'), _cancel, 110, 34,
           '#14142a', '#1e1e42', '#7c6fff', '#c0c0e0',
           ('Segoe UI', 9)).pack(side=tk.RIGHT)
        self.root.wait_window(_ov)
        if not _ok[0]: return
        chosen = [zp for zp, var in _sel_vars.items() if var.get()]
        if not chosen:
            _messagebox.showinfo(_tr(self, 'inject.info_title'), _tr(self, 'inject.no_zips_msg'))
            return
        self.log(f"Seçilen: {len(chosen)}/{len(zips)} zip")
        self._set_indicator(f"{len(chosen)} zip seçildi, inject başlıyor...", 'working')
        depot_dir = Path("C:\\Program Files (x86)\\Steam\\config\\depotcache")
        stplug_dir = Path("C:\\Program Files (x86)\\Steam\\config\\stplug-in")
        depot_dir.mkdir(parents=True, exist_ok=True); stplug_dir.mkdir(parents=True, exist_ok=True)
        used_dir = games_dir / "used"
        used_dir.mkdir(parents=True, exist_ok=True)
        ini_path = used_dir / "injected_games.ini"
        _config = _configparser.ConfigParser()
        if ini_path.exists():
            try: _config.read(str(ini_path), encoding='utf-8')
            except: pass
        if 'Games' not in _config: _config['Games'] = {}
        done = 0
        for zip_path in chosen:
            try:
                self.log(f"[{zip_path.name}] işleniyor...")
                with _zipfile.ZipFile(zip_path, 'r') as zf:
                    entries = [info for info in zf.infolist() if not info.is_dir()]
                    self.log(f"  -> {len(entries)} dosya bulundu")
                    for info in entries:
                        target = depot_dir if info.filename.endswith('.manifest') else stplug_dir
                        flat_name = Path(info.filename).name
                        tag = 'manifest' if info.filename.endswith('.manifest') else 'lua/st'
                        self.log(f"     [{tag}] {flat_name} -> {target.name}/")
                        (target / flat_name).write_bytes(zf.read(info))
                game_name = zip_path.stem.replace('_', ' ').replace('-', ' ').strip()
                game_name = ' '.join(w.capitalize() for w in game_name.split())
                ts = _time.strftime('%Y-%m-%d %H:%M')
                _config['Games'][game_name] = ts
                dest = used_dir / zip_path.name
                _shutil.move(str(zip_path), str(dest))
                self.log(f"[{zip_path.name}] -> used/ taşındı, {game_name} kaydedildi"); done += 1
            except Exception as e:
                self.log(f"[{zip_path.name}] HATA: {e}")
        try:
            with open(str(ini_path), 'w', encoding='utf-8') as f:
                _config.write(f)
        except: pass
        self.log(f"{done}/{len(zips)} inject edildi.")
        self._set_indicator(_tr(self, 'indicator.done'), 'online' if done > 0 else 'offline')
        if done > 0: _play_sound('done')
        else: _play_sound('error')
        if done > 0 and _messagebox.askyesno(_tr(self, 'inject.done_title'), _tr(self, 'inject.ask_restart').format(count=done)):
            g['save_settings'](self.settings)
            self.log("Steam kapatılıyor...")
            self._set_indicator(_tr(self, 'indicator.steam_stop'), 'working')
            _subprocess.run(["taskkill", "/f", "/im", "steam.exe"], capture_output=True)
            _time.sleep(5)
            self.log("Steam başlatılıyor...")
            self._set_indicator(_tr(self, 'indicator.steam_start'), 'working')
            _subprocess.Popen(["C:\\Program Files (x86)\\Steam\\steam.exe"])
            self.log("Steam yeniden başlatıldı.")
    SteamApp.batch_inject_all = batch_inject_all

    # ---- Inject OF Browser (per-game extracted OF inject) ----
    def _inject_of_browser(self):
        _tk_fd2 = __import__('tkinter.filedialog')
        base_dir = Path(__file__).resolve().parent
        saved = self.settings.get('save_path', '') or self.settings.get('new_games_folder', '')
        games_dir = Path(saved) if saved and Path(saved).exists() else base_dir / "1 New Games"
        # Scan for extracted OF folders (contain .exe)
        _exe_folders = []
        for _root, _dirs, _files in os.walk(str(games_dir)):
            _has_exe = any(f.lower().endswith('.exe') for f in _files)
            if _has_exe:
                _folder_name = Path(_root).name
                _exe_path = next((Path(_root) / f for f in _files if f.lower().endswith('.exe')), None)
                if _exe_path:
                    _exe_folders.append({'folder': Path(_root), 'exe': _exe_path, 'name': _folder_name})
        _parent = getattr(self, 'results_canvas', None) or getattr(self, 'cards_frame', None) or self.root
        _ov = tk.Frame(self.root, bg='#08080e', highlightthickness=1, highlightbackground='#1a1a30')
        _ov.place(x=0, y=0, relwidth=1, relheight=1, anchor='nw')
        _ov.lift()
        _top = tk.Frame(_ov, bg='#08080e')
        _top.pack(fill=tk.X, padx=16, pady=(14, 6))
        tk.Label(_top, text=_tr(self, 'inject_of.select_title'),
                 font=('Bahnschrift SemiBold', 18), fg='#e0e0f0', bg='#08080e').pack(side=tk.LEFT)
        _sel_vars = {}
        _path_vars = {}
        _cf = tk.Frame(_ov, bg='#0a0a16')
        _cf.pack(fill=tk.BOTH, expand=True, padx=16, pady=(8, 10))
        _canv = tk.Canvas(_cf, bg='#0a0a16', highlightthickness=0)
        _scr = ttk.Scrollbar(_cf, orient=tk.VERTICAL, command=_canv.yview)
        _inner = tk.Frame(_canv, bg='#0a0a16')
        _inner.bind('<Configure>', lambda e: _canv.configure(scrollregion=_canv.bbox('all')))
        _canv.create_window((0, 0), window=_inner, anchor='nw')
        _canv.configure(yscrollcommand=_scr.set)
        _canv.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        _scr.pack(side=tk.RIGHT, fill=tk.Y)
        def _mw(e): _canv.yview('scroll', -e.delta//30, 'units')
        _canv.bind('<MouseWheel>', _mw)
        if not _exe_folders:
            _lng = self.settings.get('language', 'tr')
            _no_folder_msg = 'Extracted OF klasoru bulunamadi.' if _lng == 'tr' else 'No extracted OF folders found.'
            tk.Label(_inner, text=_no_folder_msg,
                     bg='#0a0a16', fg='#686880', font=('Segoe UI', 12)).pack(pady=40)
        else:
            for i, _ef in enumerate(_exe_folders):
                var = tk.BooleanVar(value=True)
                _sel_vars[_ef['folder']] = var
                bg = '#0c0c20' if i % 2 == 0 else '#0a0a16'
                row = tk.Frame(_inner, bg=bg)
                row.pack(fill=tk.X, padx=6, pady=1)
                tk.Checkbutton(row, variable=var, bg=bg, activebackground='#14142a',
                               selectcolor='#7c6fff', fg='#d0d0e8', font=('Segoe UI', 10)).pack(side=tk.LEFT)
                tk.Label(row, text=_ef['name'], bg=bg, fg='#d0d0e8',
                         font=('Segoe UI', 10), anchor='w', width=25).pack(side=tk.LEFT, fill=tk.X, expand=True, padx=4)
                _exe_name_lbl = tk.Label(row, text=_ef['exe'].name, bg=bg, fg='#686880',
                         font=('Segoe UI', 8), anchor='e', width=30)
                _exe_name_lbl.pack(side=tk.RIGHT, padx=4)
                _browse_var = [str(_ef['exe'])]
                _path_vars[_ef['folder']] = _browse_var
                def _make_browse(_fld, _var, _lbl):
                    def _browse():
                        _p = _tk_fd_imp.askopenfilename(title='Select .exe for ' + _fld.name,
                            filetypes=[('Executable files', '*.exe'), ('All files', '*.*')])
                        if not _p: return
                        _var[0] = _p
                        _lbl.config(text=Path(_p).name)
                    return _browse
                AB4 = g.get('AnimatedButton', AnimatedButton)
                AB4(row, '...', _make_browse(_ef['folder'], _browse_var, _exe_name_lbl), 28, 24,
                    '#1f3348', '#2b4b68', '#66c0f4', '#ffffff',
                    ('Segoe UI', 8)).pack(side=tk.RIGHT, padx=2)
        _btnf = tk.Frame(_ov, bg='#08080e')
        _btnf.pack(fill=tk.X, padx=16, pady=(0, 14))
        _tk_fd_imp = __import__('tkinter.filedialog')
        def _add_folder():
            _sel = _tk_fd_imp.askdirectory(title=_tr(self, 'inject.select_title'))
            if not _sel: return
            _sp = Path(_sel)
            _exes = list(_sp.glob('*.exe'))
            if not _exes:
                _messagebox.showinfo(_tr(self, 'inject.info_title'), 'No .exe found in selected folder.')
                return
            _exe_folders.append({'folder': _sp, 'exe': _exes[0], 'name': _sp.name})
            _ov.destroy()
            self._inject_of_browser()
        _ok = [False]
        def _confirm():
            _ok[0] = True; _ov.destroy()
        def _cancel():
            _ov.destroy()
        AB = g.get('AnimatedButton', AnimatedButton)
        AB(_btnf, _tr(self, 'button.add_folder'), _add_folder, 120, 34,
           '#1c1c3a', '#2a2a5a', '#7c6fff', '#e0e0f0',
           ('Segoe UI Semibold', 9)).pack(side=tk.LEFT, padx=(0, 8))
        AB(_btnf, _tr(self, 'inject.select_inject'), _confirm, 140, 34,
           '#1c1c3a', '#2a2a5a', '#7c6fff', '#e0e0f0',
           ('Segoe UI Semibold', 10)).pack(side=tk.RIGHT, padx=(8, 0))
        AB(_btnf, _tr(self, 'button.close'), _cancel, 110, 34,
           '#14142a', '#1e1e42', '#7c6fff', '#c0c0e0',
           ('Segoe UI', 9)).pack(side=tk.RIGHT)
        self.root.wait_window(_ov)
        if not _ok[0]: return
        chosen = [fp for fp, var in _sel_vars.items() if var.get()]
        if not chosen:
            _messagebox.showinfo(_tr(self, 'inject.info_title'), 'No folders selected.')
            return
        stplug_dir = Path("C:\\Program Files (x86)\\Steam\\config\\stplug-in")
        stplug_dir.mkdir(parents=True, exist_ok=True)
        _steam_common = Path("C:\\Program Files (x86)\\Steam\\steamapps\\common")
        done = 0
        for _folder in chosen:
            try:
                _custom_exe = Path(_path_vars.get(_folder, [''])[0]) if _path_vars.get(_folder) else None
                _exe_file = _custom_exe if (_custom_exe and _custom_exe.suffix.lower() == '.exe' and _custom_exe.exists()) else None
                if not _exe_file:
                    for f in _folder.iterdir():
                        if f.suffix.lower() == '.exe':
                            _exe_file = f; break
                if not _exe_file:
                    self.log(f'[Inject OF] No .exe in {_folder.name}')
                    continue
                _lua_file = _folder / (_exe_file.stem + '.lua')
                # Find installed game folder matching this OF
                _game_name = _folder.name.replace('_', ' ').replace('-', ' ').strip()
                _game_name = ' '.join(w.capitalize() for w in _game_name.split())
                _target_dir = None
                for _gd in _steam_common.iterdir():
                    if _gd.is_dir() and (_game_name.lower() in _gd.name.lower() or _gd.name.lower() in _game_name.lower()):
                        _target_dir = _gd; break
                # Also check via Steam .acf for appid
                if not _target_dir and hasattr(self, '_find_steam_game_path'):
                    try:
                        _found = self._find_steam_game_path(_exe_file.stem)
                        if _found: _target_dir = Path(_found)
                    except: pass
                if not _target_dir:
                    _target_dir = _steam_common / _folder.name
                if not _target_dir.exists():
                    self.log(f'[Inject OF] Oyun yuklu degil, atlaniyor: {_game_name}')
                    continue
                # Copy folder contents (not folder itself) to target dir
                for _src_file in _folder.iterdir():
                    if _src_file.is_file():
                        _dst = _target_dir / _src_file.name
                        try:
                            _shutil.copy2(str(_src_file), str(_dst))
                            self.log(f'[Inject OF] {_src_file.name} -> {_target_dir.name}/')
                        except Exception as _cp_err:
                            self.log(f'[Inject OF] Kopyalama hatasi {_src_file.name}: {_cp_err}')
                # Copy .lua companion to stplug-in
                if _lua_file.exists():
                    try:
                        _shutil.copy2(str(_lua_file), str(stplug_dir / _lua_file.name))
                        self.log(f'[Inject OF] Lua: {_lua_file.name} -> stplug-in/')
                    except Exception as _lua_err:
                        self.log(f'[Inject OF] Lua hatasi: {_lua_err}')
                done += 1
            except Exception as _ex:
                self.log(f'[Inject OF] HATA: {_ex}')
        self._set_indicator(_tr(self, 'indicator.done'), 'online' if done > 0 else 'offline')
        if done > 0:
            _messagebox.showinfo(_tr(self, 'inject.done_title'), f'{done} inject edildi.')
    SteamApp._inject_of_browser = _inject_of_browser

    # Add Inject All button to header
    _root_app = g.get('app')
    if _root_app is not None:
        try:
            _header_btn = getattr(_root_app, 'header_btn_ayar', None)
            _parent = _header_btn.master if _header_btn is not None else _root_app
            AB = g.get('AnimatedButton', AnimatedButton)

            AB(_parent, _tr(_root_app, 'button.inject_all'), _root_app.batch_inject_all, 100, 30,
               '#244363', '#315f8e', '#66c0f4', '#f7fafc',
               ('Segoe UI Semibold', 9)).pack(side=tk.RIGHT, padx=6)
        except Exception:
            pass

    # ---- LuaTools: redirect walftech download URL at requests.Session class level ----
    try:
        import requests as _req2, re as _re2
        _orig_session_get = _req2.Session.get
        _LUATOOLS_URLS = [
            'https://raw.githubusercontent.com/sushi-dev55-alt/sushitools-games-repo-alt/main/{}.zip',
            'http://167.235.229.108/{}',
            'https://files.luatools.work/GameBypasses/{}.zip',
        ]
        def _luatools_get(self, url, *args, **kwargs):
            if 'walftech.com' in url and 'proxy.php' in url:
                m = _re2.search(r'id=(\d+)', url)
                if m:
                    appid = m.group(1)
                    for _lu in _LUATOOLS_URLS:
                        try:
                            _r = _orig_session_get(self, _lu.format(appid), *args, **kwargs)
                            if _r and _r.status_code == 200:
                                return _r
                        except: pass
            return _orig_session_get(self, url, *args, **kwargs)
        _req2.Session.get = _luatools_get
    except:
        pass

    # ---- LuaTools: disk cache for lua.tools responses ----
    _LUA_CACHE_DIR = Path(os.environ.get('LOCALAPPDATA', Path(__file__).resolve().parent)) / 'SteamToolsLua' / 'cache'
    try: _LUA_CACHE_DIR.mkdir(parents=True, exist_ok=True)
    except: pass
    def _lua_cache_get(key):
        import json as _cj, time as _ct
        _fp = _LUA_CACHE_DIR / f'{key}.json'
        try:
            if _fp.exists():
                _d = _cj.loads(_fp.read_text('utf-8'))
                if _ct.time() - _d.get('ts', 0) < 1800: return _d.get('data')
        except: pass
        return None
    def _lua_cache_set(key, data):
        import json as _cj, time as _ct
        try:
            _fp = _LUA_CACHE_DIR / f'{key}.json'
            _fp.write_text(_cj.dumps({'ts': _ct.time(), 'data': data}), 'utf-8')
        except: pass
    # ---- Game Files & Outside Games directories (dynamic, under 1 New Games) ----
    def _get_1ng_base():
        _base = Path(__file__).resolve().parent
        try:
            _saved = getattr(_root_app, 'settings', {}).get('save_path', '') or getattr(_root_app, 'settings', {}).get('new_games_folder', '')
            if _saved and Path(_saved).exists(): _base = Path(_saved)
        except: pass
        return _base
    def _get_game_files_dir(): _d = _get_1ng_base() / "Game Files"; _d.mkdir(parents=True, exist_ok=True); return _d
    def _get_outside_games_dir(): _d = _get_1ng_base() / "Outside Games"; _d.mkdir(parents=True, exist_ok=True); return _d
    # ---- LuaTools: standalone download helper for batch & single use ----
    _LUA_DL_LIBRARIES = []
    _LUA_DL_STEAM_PATH = Path("C:\\Program Files (x86)\\Steam")
    _LUA_DL_LIBRARIES.append(_LUA_DL_STEAM_PATH / "steamapps")
    _LUA_DL_VDF = _LUA_DL_STEAM_PATH / "steamapps" / "libraryfolders.vdf"
    if _LUA_DL_VDF.exists():
        try:
            for _line in _LUA_DL_VDF.read_text('utf-8', errors='replace').split('\n'):
                _m = re.search(r'"path"\s+"([^"]+)"', _line)
                if _m: _LUA_DL_LIBRARIES.append(Path(_m.group(1)) / "steamapps")
        except: pass
    def _luatools_download_game(appid, gamename, parent_win=None):
        try:
            import requests as _req, re as _lre, json as _ljson, zipfile as _zf, io as _io
            _releases = _lua_cache_get(f'fixes_{appid}')
            if not isinstance(_releases, list) or not _releases:
                _releases = None
                _r = _req.get(f'https://lua.tools/fixes/{appid}', headers={'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'}, timeout=15)
                if _r.status_code != 200: return False, f'Sayfa yuklenemedi (HTTP {_r.status_code})'
                _pat = r"self\.__next_f\.push\(\[1,\"((?:[^\"\\]|\\.)*)\"\]\)"
                _text = ''
                for _m in _lre.finditer(_pat, _r.text):
                    _part = _m.group(1)
                    _part = _part.replace('\\"', '"').replace('\\n', '\n')
                    _text += _part
                _idx = _text.find('"releases":[')
                if _idx >= 0:
                    _start = _idx
                    _depth = 0
                    while _start >= 0:
                        if _text[_start] == '[':
                            if _depth == 0: break
                            _depth -= 1
                        elif _text[_start] == ']':
                            _depth += 1
                        _start -= 1
                    _depth = 0
                    for _end in range(_idx, len(_text)):
                        if _text[_end] == '[': _depth += 1
                        elif _text[_end] == ']':
                            _depth -= 1
                            if _depth == 0: break
                    try: _releases = _ljson.loads(_text[_start:_end+1])
                    except: pass
                if not _releases:
                    _idx2 = _text.find('"releases"')
                    if _idx2 >= 0:
                        for _line in _text[_idx2:_idx2+2000].split('\n'):
                            _line = _line.strip()
                            if not _line: continue
                            try:
                                _d = _ljson.loads(_line)
                                if isinstance(_d, list):
                                    for _item in _d:
                                        if isinstance(_item, dict) and 'releases' in _item:
                                            _releases = _item['releases']
                            except: pass
                if isinstance(_releases, list): _lua_cache_set(f'fixes_{appid}', _releases)
            if not _releases: return False, 'Release bulunamadi'
            _dl_url = None
            if len(_releases) == 1:
                _dl_url = _releases[0].get('downloadUrl', '')
            else:
                try:
                    import tkinter.simpledialog as _lsd
                    _titles = [_rel.get('title', f'Release {i}') for i, _rel in enumerate(_releases)]
                    _choice = _lsd.askinteger('Surum Sec',
                        f'{gamename} - Hangi surum indirilsin? (1-{len(_releases)})',
                        minvalue=1, maxvalue=len(_releases), initialvalue=1)
                    if _choice: _dl_url = _releases[_choice-1].get('downloadUrl', '')
                except: _dl_url = _releases[0].get('downloadUrl', '')
            if not _dl_url: return False, 'Indirme URL bulunamadi'
            _resp = _req.get(_dl_url, timeout=120)
            if _resp.status_code != 200: return False, f'Zip indirilemedi (HTTP {_resp.status_code})'
            _gd = _get_game_files_dir() / gamename
            _gd.mkdir(parents=True, exist_ok=True)
            _count = 0
            with _zf.ZipFile(_io.BytesIO(_resp.content)) as _z:
                for _name in _z.namelist():
                    try: _z.extract(_name, str(_gd)); _count += 1
                    except: pass
            return True, f'{_count} dosya ayiklandi -> {_gd}'
        except Exception as _ex:
            return _luatools_download_game(appid, gamename, parent_win)

    def _walftech_download_game(appid, gamename, parent_win=None):
        try:
            import requests as _wreq, zipfile as _wzf, io as _wio
            _urls = [
                f'https://raw.githubusercontent.com/sushi-dev55-alt/sushitools-games-repo-alt/main/{appid}.zip',
                f'http://167.235.229.108/{appid}',
                f'https://files.luatools.work/GameBypasses/{appid}.zip',
            ]
            _headers = {'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'}
            _zip_data = None
            for _u in _urls:
                try:
                    _wr = _wreq.get(_u, headers=_headers, timeout=30)
                    if _wr.status_code == 200:
                        _zip_data = _wr.content
                        break
                except: pass
            if not _zip_data:
                return _luatools_download_game(appid, gamename, parent_win)
            _gd = _get_game_files_dir() / gamename
            _gd.mkdir(parents=True, exist_ok=True)
            _count = 0
            with _wzf.ZipFile(_wio.BytesIO(_zip_data)) as _wz:
                for _name in _wz.namelist():
                    try: _wz.extract(_name, str(_gd)); _count += 1
                    except: pass
            return True, f'{_count} dosya ayiklandi -> {_gd}'
        except Exception as _ex:
            return _luatools_download_game(appid, gamename, parent_win)

    def _inject_outside_games():
        _dir = _get_outside_games_dir()
        if not _dir.exists() or not any(_dir.iterdir()):
            _messagebox.showinfo('Outside Games', 'Outside Games klasoru bos.\nDosyalari klasore atip tekrar deneyin.')
            return
        _subdirs = [d for d in _dir.iterdir() if d.is_dir()]
        if not _subdirs:
            _messagebox.showinfo('Outside Games', 'Alt klasor bulunamadi.')
            return
        depot_dir = Path("C:\\Program Files (x86)\\Steam\\config\\depotcache")
        stplug_dir = Path("C:\\Program Files (x86)\\Steam\\config\\stplug-in")
        depot_dir.mkdir(parents=True, exist_ok=True); stplug_dir.mkdir(parents=True, exist_ok=True)
        _done = 0
        for _sd in _subdirs:
            try:
                _name = _sd.name
                _files = list(_sd.iterdir())
                if not _files: continue
                for _f in _files:
                    if _f.suffix.lower() == '.manifest':
                        try:
                            _dst = depot_dir / _f.name
                            if not _dst.exists():
                                _shutil.copy2(str(_f), str(_dst))
                        except: pass
                    elif _f.suffix.lower() == '.lua':
                        try:
                            _dst = stplug_dir / _f.name
                            if not _dst.exists():
                                _shutil.copy2(str(_f), str(_dst))
                        except: pass
                    else:
                        _try_game_dir = False
                        for _lib in _LUA_DL_LIBRARIES:
                            _acf = _lib / f"appmanifest_{_name}.acf"
                            if _acf.exists():
                                try:
                                    _txt = _acf.read_text('utf-8', errors='replace')
                                    _mm = re.search(r'"installdir"\s+"([^"]+)"', _txt)
                                    if _mm:
                                        _cd = _lib.parent / "steamapps" / "common" / _mm.group(1)
                                        if _cd.exists():
                                            _shutil.copy2(str(_f), str(_cd / _f.name))
                                            _try_game_dir = True
                                except: pass
                        if not _try_game_dir:
                            _shutil.copy2(str(_f), str(_dir))
                _done += 1
            except: pass
        _messagebox.showinfo('Outside Games', f'{_done} oyun inject edildi.\nDosyalar depotcache/stplug-in/game klasorlerine kopyalandi.')

