    # ---- Ban check (periodic, every 30s) ----
    def _show_ban_popup(bt, bid, brem=None):
        try:
            _ar = g.get('app')
            _rw = getattr(_ar, 'root', None) if _ar else None
            if _rw:
                try: _rw.withdraw()
                except: pass
            import tkinter as _tk
            _bp = _tk.Toplevel(_rw) if _rw else _tk.Tk()
            _bp.title('Banlandiniz')
            _bp.attributes('-topmost', True)
            _bp.configure(bg='#0a0a10')
            if _rw:
                _bw, _bh = _rw.winfo_screenwidth(), _rw.winfo_screenheight()
                _bp.geometry(f'500x280+{(_bw-500)//2}+{(_bh-280)//2}')
            else:
                _bp.geometry('500x280+200+200')
            _bp.resizable(False, False)
            _fr = _tk.Frame(_bp, bg='#0a0a10')
            _fr.pack(expand=True, fill='both')
            _tk.Label(_fr, text='BANLANDINIZ', fg='#f56565', bg='#0a0a10',
                      font=('Segoe UI', 22, 'bold')).pack(pady=(30, 5))
            _tk.Label(_fr, text=bid.upper(), fg='#686880', bg='#0a0a10',
                      font=('Consolas', 10)).pack()
            if bt == 'permanent':
                _tk.Label(_fr, text='Suresiz Ban', fg='#e06060', bg='#0a0a10',
                          font=('Segoe UI', 14)).pack(pady=(15, 5))
            else:
                _tl = _tk.Label(_fr, text='', fg='#7c6fff', bg='#0a0a10',
                                font=('Segoe UI', 30, 'bold'))
                _tl.pack(pady=(15, 5))
                _tk.Label(_fr, text='kalan sure', fg='#585878', bg='#0a0a10',
                          font=('Segoe UI', 11)).pack()
                def _cnt(lbl, s):
                    if s <= 0:
                        lbl.config(text='Suresi doldu!', fg='#48bb78'); return
                    h, r = divmod(s, 3600); m, sc = divmod(r, 60)
                    lbl.config(text=f'{h:02d}:{m:02d}:{sc:02d}')
                    lbl.after(1000, _cnt, lbl, s - 1)
                _cnt(_tl, brem)
            _tk.Button(_fr, text='Uygulamayi Kapat', command=_bp.destroy,
                      bg='#244363', fg='#66c0f4', font=('Segoe UI', 11),
                      relief='flat', padx=20, pady=6).pack(pady=(20, 10))
        except:
            pass

    _ROOT = getattr(g.get('app'), 'root', None) if g.get('app') else None

    _MY_NICKNAME = {'nickname': ''}

    def _check_ban():
        def _task():
            try:
                import requests as _rq
                _tk = ''.join(chr(b ^ _XOR_KEY) for b in _XOR_TOKEN)
                _r = _rq.get(f'https://api.github.com/gists/{_ADMIN_GIST}',
                             headers={'Authorization': f'token {_tk}', 'User-Agent': 'SteamToolsLua'}, timeout=8)
                if _r.status_code != 200: return
                _data = _r.json().get('files', {}).get('blacklist.json', {}).get('content', '')
                if not _data: return
                _bl = json.loads(_data)
                _bans = _bl.get('bans', [])
                if not _bans: return
                _pc2 = os.environ.get('COMPUTERNAME', 'Unknown').lower()
                _hwid2 = _get_hwid().lower()
                import datetime as _dt4
                _now2 = _dt4.datetime.utcnow()
                for _b in _bans:
                    _p = _b.split(':')
                    _bid = _p[0].lower()
                    if _bid != _pc2 and _bid != _hwid2: continue
                    if len(_p) <= 2:
                        if _ROOT: _ROOT.after(0, _show_ban_popup, 'permanent', _bid)
                        return
                    _ds2 = _p[-1]
                    _ts2 = ':'.join(_p[1:-1])
                    _st = None
                    for _fmt in ('%Y-%m-%dT%H:%M:%SZ', '%Y%m%dT%H%M%SZ'):
                        try: _st = _dt4.datetime.strptime(_ts2, _fmt); break
                        except: pass
                    if _st is None:
                        if _ROOT: _ROOT.after(0, _show_ban_popup, 'permanent', _bid); return
                    _sc = 0
                    _u2 = _ds2[-1]
                    try: _n2 = int(_ds2[:-1])
                    except:
                        if _ROOT: _ROOT.after(0, _show_ban_popup, 'permanent', _bid); return
                    if _u2 == 'm': _sc = _n2 * 60
                    elif _u2 == 'h': _sc = _n2 * 3600
                    elif _u2 == 'd': _sc = _n2 * 86400
                    else:
                        if _ROOT: _ROOT.after(0, _show_ban_popup, 'permanent', _bid); return
                    _rm2 = int((_st + _dt4.timedelta(seconds=_sc) - _now2).total_seconds())
                    if _rm2 > 0:
                        if _ROOT: _ROOT.after(0, _show_ban_popup, 'timed', _bid, _rm2)
                        return
            except:
                pass
        threading.Thread(target=_task, daemon=True).start()

    def _fetch_nicknames():
        def _task():
            try:
                _tk2 = ''.join(chr(b ^ _XOR_KEY) for b in _XOR_TOKEN)
                _r2 = __import__('requests').get(f'https://api.github.com/gists/{_ADMIN_GIST}',
                             headers={'Authorization': f'token {_tk2}', 'User-Agent': 'SteamToolsLua'}, timeout=8)
                if _r2.status_code != 200: return
                _nf = _r2.json().get('files', {}).get('nicknames.json', {}).get('content', '')
                if not _nf: return
                _nd = json.loads(_nf)
                _hw = _get_hwid().lower()
                _entry = _nd.get(_hw)
                if _entry and _entry.get('nickname'):
                    _MY_NICKNAME['nickname'] = _entry['nickname']
                    threading.Thread(target=_log_device, daemon=True).start()
            except:
                pass
        threading.Thread(target=_task, daemon=True).start()

    if _ROOT:
        def _check_loop():
            _check_ban()
            _fetch_nicknames()
            try: _ROOT.after(30000, _check_loop)
            except: pass
        try: _ROOT.after(5000, _check_loop)
        except: pass

