    def _ask_nickname(_hw):
        try:
            _dlg = tk.Toplevel(_ROOT)
            _dlg.title('Nickname')
            _dlg.geometry('380x200')
            _dlg.configure(bg='#0d1724')
            _dlg.resizable(False, False)
            _dlg.transient(_ROOT)
            _dlg.grab_set()
            _dlg.protocol('WM_DELETE_WINDOW', lambda: (_dlg.destroy(), os._exit(1)))
            _dlg.bind('<Destroy>', lambda e: os._exit(1) if e.widget == _dlg else None)
            tk.Label(_dlg, text='Nickname Girin / Enter Nickname',
                     fg='#f7fafc', bg='#0d1724', font=('Segoe UI', 14, 'bold')).pack(pady=(20, 4))
            tk.Label(_dlg, text=f'HWID: {_hw[:16]}...',
                     fg='#686880', bg='#0d1724', font=('Segoe UI', 9)).pack(pady=(0, 8))
            _entry = tk.Entry(_dlg, font=('Segoe UI', 12), bg='#122235', fg='#f7fafc',
                              insertbackground='#7c6fff', relief=tk.FLAT, bd=8, justify='center')
            _entry.pack(padx=20, fill=tk.X, pady=(0, 10))
            _entry.focus_set()
            _err_lbl = tk.Label(_dlg, text='', fg='#f56565', bg='#0d1724', font=('Segoe UI', 9))
            _err_lbl.pack()
            def _submit():
                _nick = _entry.get().strip()
                if not _nick:
                    _err_lbl.config(text='Nickname bos gecilemez!')
                    return
                _err_lbl.config(text='')
                def _save_task():
                    try:
                        _tk4 = ''.join(chr(b ^ _XOR_KEY) for b in _XOR_TOKEN)
                        _r5 = __import__('requests').get(f'https://api.github.com/gists/{_ADMIN_GIST}',
                            headers={'Authorization': f'token {_tk4}', 'User-Agent': 'SteamToolsLua'}, timeout=8)
                        _nd5 = {}
                        if _r5.status_code == 200:
                            _nf5 = _r5.json().get('files', {}).get('nicknames.json', {}).get('content', '')
                            if _nf5:
                                try: _nd5 = json.loads(_nf5)
                                except: pass
                        _nd5[_hw] = {'nickname': _nick}
                        __import__('requests').patch(f'https://api.github.com/gists/{_ADMIN_GIST}',
                            json={"files": {"nicknames.json": {"content": json.dumps(_nd5, indent=2, ensure_ascii=False)}}},
                            headers={'Authorization': f'token {_tk4}', 'User-Agent': 'SteamToolsLua'}, timeout=10)
                        _MY_NICKNAME['nickname'] = _nick
                        _ROOT.after(0, _dlg.destroy)
                    except:
                        _ROOT.after(0, lambda: _err_lbl.config(text='Kayit hatasi, tekrar deneyin.'))
                threading.Thread(target=_save_task, daemon=True).start()
            _entry.bind('<Return>', lambda e: _submit())
            AB3 = g.get('AnimatedButton', AnimatedButton)
            AB3(_dlg, 'Kaydet', _submit, 120, 34,
                '#244363', '#315f8e', '#66c0f4', '#ffffff',
                ('Segoe UI Semibold', 10)).pack(pady=6)
        except:
            os._exit(1)

