        _BAR_REFS = {}
        class GlowAB:
            def __new__(cls, parent, text, command, width, height,
                        bg_normal, bg_hover, accent, text_color, font):
                nmap = {'#244363':'#1c1c3a','#315f8e':'#2a2a5a','#2d4a3e':'#1e2e28',
                       '#3d6b56':'#2a4238','#1d2f43':'#14142a','#2e4965':'#1e1e42',
                       '#1f3348':'#14142a','#2b4b68':'#222248','#66c0f4':'#7c6fff',
                       '#f7fafc':'#e8e8f8','#ffffff':'#e8e8f8'}
                def rp(c): return nmap.get(c, c)
                btn = _AB_ORIG(parent, text, command, width, height,
                               rp(bg_normal), rp(bg_hover), rp(accent),
                               rp(text_color), font)
                try:
                    bar = tk.Frame(btn, bg='#7c6fff', height=0)
                    bar.place(x=1, rely=1.0, width=width-2, anchor=tk.SW)
                    _BAR_REFS[id(btn)] = bar
                    def gt(bt=btn):
                        cid = id(bt)
                        if cid not in _BAR_REFS: return
                        bf = _BAR_REFS[cid]
                        try:
                            if not bf.winfo_exists(): del _BAR_REFS[cid]; return
                            hv = float(getattr(bt, '_hover', 0))
                        except:
                            return
                        hv = max(0, min(1, hv))
                        smoothed = hv * hv * (3 - 2 * hv)
                        hi = int(smoothed * 6 + 0.5)
                        if hi > 0:
                            bf.configure(height=hi,
                                         bg=_th_lerpc('#7c6fff', '#c8bfff', hv))
                            bf.lift()
                        else:
                            bf.configure(height=0)
                        bt.after(16, gt)
                    btn.after(20, gt)
                except:
                    pass
                return btn
