    # ---- SteamDB Game Browser + Sidebar + Library ----
    _steamdb_path = _data_dir / "steamdb_cache.json"
    _STEAMDB_LIMIT = 10000
    _STEAMDB_PAGE_SIZE = 12

    def _fetch_steamdb_games(offset=0, progress_callback=None):
        import json, time
        try:
            if progress_callback:
                progress_callback(5, 'SteamSpy sunucusuna baglaniliyor...')
            resp = g['session'].get(
                'https://steamspy.com/api.php?request=all',
                timeout=60, stream=True
            )
            total_len = resp.headers.get('Content-Length')
            if total_len:
                total_len = int(total_len)
            chunks = []
            downloaded = 0
            for chunk in resp.iter_content(chunk_size=65536):
                if chunk:
                    chunks.append(chunk)
                    downloaded += len(chunk)
                    if progress_callback and total_len:
                        pct = min(70, int(downloaded / total_len * 70))
                        progress_callback(pct, f'Indiriliyor... {downloaded // 1024}KB / {total_len // 1024}KB')
            raw = b''.join(chunks)
            if progress_callback:
                progress_callback(75, 'JSON cozumleniyor...')
            data = json.loads(raw)
            if progress_callback:
                progress_callback(80, 'Oyunlar filtreleniyor...')
            all_games = []
            skip_kw = ['soundtrack', 'sdk', 'tool', 'dlc', 'demo', 'ost',
                      'artbook', 'wallpaper', 'music', 'trailer', 'video',
                      'chapter', 'package', 'server', 'dedicated', 'workshop',
                      'editor', 'runtime', 'redistributable', 'benchmark',
                      'controller', 'configuration', 'vpn',
                      'sound track', 'art book', 'original soundtrack',
                      'redist', 'installer', 'app pack']
            total_items = len(data)
            for idx, (appid_str, info) in enumerate(data.items()):
                name = (info.get('name') or '').strip()
                if not name:
                    continue
                nl = name.lower()
                if any(kw in nl for kw in skip_kw):
                    continue
                all_games.append({
                    'appid': str(info['appid']),
                    'name': name,
                    'image_url': f'https://shared.akamai.steamstatic.com/store_item_assets/steam/apps/{info["appid"]}/header.jpg',
                    'meta': 'SteamDB',
                    'footer': ''
                })
                if progress_callback and idx % 500 == 0:
                    pct = min(90, 80 + int(idx / max(total_items, 1) * 10))
                    progress_callback(pct, f'Filtreleniyor... {idx}/{total_items}')
            if progress_callback:
                progress_callback(92, 'Siralamyor...')
            all_games.sort(key=lambda x: int(x.get('appid', '0')), reverse=True)
            total = len(all_games)
            if progress_callback:
                progress_callback(95, 'Onbellege kaydediliyor...')
            cache = {'ts': time.time(), 'games': all_games, 'total': total}
            _steamdb_path.write_text(json.dumps(cache, ensure_ascii=False), encoding='utf-8')
            if progress_callback:
                progress_callback(100, 'Tamam!')
            return all_games[offset:offset + _STEAMDB_LIMIT]
        except Exception as ex:
            print(f'SteamDB fetch: {ex}')
            if progress_callback:
                progress_callback(-1, f'Hata: {ex}')
            return []

    def _load_steamdb_games(offset=0):
        import json
        try:
            data = json.loads(_steamdb_path.read_text(encoding='utf-8'))
            games = data.get('games', [])
            return games[offset:offset + _STEAMDB_LIMIT]
        except:
            pass
        return []

    def _steamdb_show_page(app, page, page_size=None):
        try:
            _eph = getattr(app, '_empty_placeholder', None)
            if _eph:
                try: _eph.destroy()
                except: pass
                app._empty_placeholder = None
            games = getattr(app, '_steamdb_games', [])
            if not games:
                for card in getattr(app, 'cards', [])[:]:
                    try: card.destroy()
                    except: pass
                app.cards.clear()
                return
            page_size = _STEAMDB_PAGE_SIZE
            total = len(games)
            total_p = max(1, (total + page_size - 1) // page_size)
            page = max(0, min(page, total_p - 1))
            start = page * page_size
            page_games = games[start:start + page_size]
            for card in getattr(app, 'cards', [])[:]:
                try: card.destroy()
                except: pass
            app.cards.clear()
            for idx, gd in enumerate(page_games):
                card = GameCard(app.cards_frame, app, gd)
                app.cards.append(card)
                if idx % 4 == 0:
                    app.root.update_idletasks()
            app.reflow_cards()
            app._sd_page = page
            app._sd_total = total_p
            if hasattr(app, '_sd_info'):
                app._sd_info.config(text=f'Sayfa {page+1}/{total_p}')
            # Track viewed pages
            viewed = getattr(app, '_sd_viewed', {})
            current_ids = {str(gd.get('appid', '') or gd.get('id', '')) for gd in page_games if gd.get('appid', '') or gd.get('id', '')}
            stored = viewed.get(page, set())
            if stored:
                overlap = len(current_ids & stored)
                if overlap < 4:
                    viewed[page] = current_ids
            else:
                viewed[page] = current_ids
            app._sd_viewed = viewed
            # Rebuild page buttons
            _rebuild_page_btns(app)
        except Exception as ex:
            print(f'SteamDB page: {ex}')

    def _rebuild_page_btns(app):
        try:
            _btns = getattr(app, '_sd_page_btns', None)
            if _btns is None:
                return
            for w in _btns.winfo_children():
                w.destroy()
            total = getattr(app, '_sd_total', 1)
            current = getattr(app, '_sd_page', 0)
            viewed = getattr(app, '_sd_viewed', {})
            def _mk_btn(p):
                is_viewed = bool(viewed.get(p, set()))
                btn = tk.Button(_btns, text=str(p+1),
                                bg='#7c6fff' if is_viewed else '#1f3348',
                                fg='#ffffff' if is_viewed else '#dce7f4',
                                relief=tk.FLAT, padx=6, pady=1,
                                font=('Segoe UI', 9),
                                activebackground='#9b8fff' if is_viewed else '#244363',
                                activeforeground='#ffffff',
                                cursor='hand2',
                                command=lambda p=p: _steamdb_show_page(app, p))
                btn.pack(side=tk.LEFT, padx=1)
            if total <= 10:
                for p in range(total):
                    _mk_btn(p)
            else:
                _mk_btn(0)
                if current > 3:
                    tk.Label(_btns, text='...', bg='#0f1b2a', fg='#585878',
                            font=('Segoe UI', 9)).pack(side=tk.LEFT)
                s = max(1, min(current - 2, total - 6))
                e = min(total - 1, max(current + 3, 7))
                if s >= e:
                    s, e = 1, min(total - 1, 8)
                for p in range(s, e):
                    _mk_btn(p)
                if current < total - 4:
                    tk.Label(_btns, text='...', bg='#0f1b2a', fg='#585878',
                            font=('Segoe UI', 9)).pack(side=tk.LEFT)
                _mk_btn(total - 1)
        except Exception as ex:
            print(f'Page btns: {ex}')

    def _build_sidebar(app):
        try:
            old = getattr(app, '_sidebar', None)
            if old is not None:
                try: old.destroy()
                except: pass
                app._sidebar = None
            sidebar = tk.Frame(app.root, bg='#06060a', width=64)
            sidebar.pack(side=tk.LEFT, fill=tk.Y)
            app._sidebar = sidebar
            icons = [
                ('🎮', lambda: _switch_tab(app, 'steamdb')),
            ]
            app._sidebar_btns = []
            for emoji, cmd in icons:
                btn = tk.Button(sidebar, text=emoji, font=('Segoe UI', 16),
                               bg='#06060a', fg='#585878', relief=tk.FLAT,
                               activebackground='#0a0a12', activeforeground='#7c6fff',
                               bd=0, padx=12, pady=8, cursor='hand2',
                               command=cmd)
                btn.pack(fill=tk.X)
                app._sidebar_btns.append(btn)
            _highlight_sidebar_btn(app, 0)
        except Exception as ex:
            print(f'Sidebar: {ex}')

    def _highlight_sidebar_btn(app, idx):
        for i, btn in enumerate(getattr(app, '_sidebar_btns', [])):
            btn.configure(fg='#7c6fff' if i == idx else '#585878',
                         bg='#0a0a12' if i == idx else '#06060a')

    def _switch_tab(app, tab):
        try:
            app._current_tab = tab
            _highlight_sidebar_btn(app, 0)
            _sd_bar = getattr(app, '_sd_bar', None)
            if _sd_bar:
                try: _sd_bar.pack(fill=tk.X, padx=20, pady=(0, 5))
                except: pass
            try:
                app.results_canvas.pack(fill=tk.BOTH, expand=True, padx=20, pady=(0, 10))
            except: pass
            if hasattr(app, '_steamdb_games'):
                _steamdb_show_page(app, getattr(app, '_sd_page', 0))
        except Exception as ex:
            print(f'Tab switch: {ex}')

    def _init_steamdb_browser():
        try:
            if not app or not hasattr(app, 'cards'):
                return
            # Set window icon
            try:
                ico = resource_path('icon.ico')
                if ico.exists():
                    app.root.iconbitmap(default=str(ico))
            except:
                pass
            try:
                import ctypes
                ctypes.windll.shell32.SetCurrentProcessExplicitAppUserModelID('steamtoolslua.1.0')
            except:
                pass
            # Load from cache only - no API call on startup
            app._sd_offset = 0
            games = _load_steamdb_games(offset=0)
            app._sd_total_games = 0
            if games:
                try:
                    import json
                    _cached = json.loads(_steamdb_path.read_text(encoding='utf-8'))
                    app._sd_total_games = _cached.get('total', len(games))
                except:
                    app._sd_total_games = len(games)
            # Build sidebar + restructure layout
            _build_sidebar(app)
            # Pagination bar
            sd_bar = tk.Frame(app.root, bg='#0f1b2a')
            sd_tag = tk.Label(sd_bar, text='SteamDB', fg='#7c6fff', bg='#0f1b2a',
                               font=('Segoe UI', 10, 'bold'))
            sd_tag.pack(side=tk.LEFT)
            sd_info = tk.Label(sd_bar, text='', fg='#8fd3ff', bg='#0f1b2a',
                               font=('Segoe UI', 10))
            sd_info.pack(side=tk.LEFT, padx=12)
            # Refresh button - always re-fetch from API with progress
            def _refresh_list():
                try:
                    _prog_frame = tk.Frame(app.root, bg='#0f1b2a')
                    _prog_frame.pack(fill=tk.X, padx=20, pady=(0, 5))
                    _prog_lbl = tk.Label(_prog_frame, text='SteamDB yenileniyor...', fg='#7c6fff',
                            bg='#0f1b2a', font=('Segoe UI', 10))
                    _prog_lbl.pack(side=tk.LEFT, padx=(0, 10))
                    _prog = ttk.Progressbar(_prog_frame, mode='determinate', length=300, maximum=100)
                    _prog.pack(side=tk.LEFT)
                    _prog_pct = tk.Label(_prog_frame, text='0%', fg='#8fd3ff',
                           bg='#0f1b2a', font=('Segoe UI', 9))
                    _prog_pct.pack(side=tk.LEFT, padx=(6, 0))
                    app.root.update()

                    def _up(pct, msg=''):
                        app.root.after(0, lambda: _du(pct, msg))
                    def _du(pct, msg):
                        if pct < 0:
                            _prog_frame.destroy()
                            return
                        _prog['value'] = pct
                        _prog_pct.config(text=f'{int(pct)}%')
                        if msg: _prog_lbl.config(text=msg)
                        if pct >= 100: app.root.after(200, _prog_frame.destroy)

                    def _fetch():
                        try:
                            app._sd_offset = 0
                            gs = _fetch_steamdb_games(offset=0, progress_callback=_up)
                            if gs:
                                app.root.after(0, lambda: _done2(gs))
                            else:
                                app.root.after(0, lambda: _prog_frame.destroy())
                        except Exception as ex:
                            app.log(f'[Refresh] {ex}')
                            _up(-1, f'Hata: {ex}')

                    def _done2(gs):
                        _prog_frame.destroy()
                        app._steamdb_games = gs
                        app._sd_page = 0
                        app._sd_viewed = {}
                        app._sd_total = max(1, (len(gs) + _STEAMDB_PAGE_SIZE - 1) // _STEAMDB_PAGE_SIZE)
                        _steamdb_show_page(app, 0)
                        app.status_var.set(f'{len(gs)} oyun yuklendi')
                        try:
                            import json
                            _cached = json.loads(_steamdb_path.read_text(encoding='utf-8'))
                            app._sd_total_games = _cached.get('total', len(gs))
                        except:
                            app._sd_total_games = len(gs)

                    threading.Thread(target=_fetch, daemon=True).start()
                except Exception as ex:
                    app.log(f'[Refresh] Hata: {ex}')
            _ref_btn = tk.Button(sd_bar, text='\U0001f504', bg='#1f3348', fg='#8fd3ff',
                relief=tk.FLAT, padx=8, pady=1, font=('Segoe UI', 12),
                activebackground='#2b4b68', activeforeground='#ffffff',
                cursor='hand2', command=_refresh_list)
            _ref_btn.pack(side=tk.LEFT, padx=(0, 8))
            _ref_btn.bind('<Enter>', lambda e: app.status_var.set(f'Sonraki {_STEAMDB_LIMIT} oyun / Refresh List'))
            _ref_btn.bind('<Leave>', lambda e: app.status_var.set(''))
            sd_nav = tk.Frame(sd_bar, bg='#0f1b2a')
            sd_nav.pack(side=tk.RIGHT)
            sd_page_btns = tk.Frame(sd_nav, bg='#0f1b2a')
            sd_page_btns.pack(side=tk.RIGHT)
            sd_prev = tk.Button(sd_nav, text='\u25c0', bg='#1f3348', fg='#dce7f4',
                                relief=tk.FLAT, padx=6, pady=1,
                                font=('Segoe UI', 10, 'bold'),
                                activebackground='#244363', activeforeground='#ffffff',
                                command=lambda: _steamdb_show_page(app, app._sd_page - 1))
            sd_prev.pack(side=tk.LEFT, padx=(0, 2))
            sd_next = tk.Button(sd_nav, text='\u25b6', bg='#1f3348', fg='#dce7f4',
                                relief=tk.FLAT, padx=6, pady=1,
                                font=('Segoe UI', 10, 'bold'),
                                activebackground='#244363', activeforeground='#ffffff',
                                command=lambda: _steamdb_show_page(app, app._sd_page + 1))
            sd_next.pack(side=tk.LEFT, padx=(2, 0))
            app._sd_bar = sd_bar
            app._sd_info = sd_info
            app._sd_prev = sd_prev
            app._sd_next = sd_next
            app._sd_page_btns = sd_page_btns
            app._sd_viewed = {}
            cinfo = app.results_canvas.pack_info()
            app.results_canvas.pack_forget()
            sd_bar.pack(fill=tk.X, padx=20, pady=(0, 5))
            app.results_canvas.pack(**cinfo)
            if games:
                app._steamdb_games = games
                _steamdb_show_page(app, 0)
            else:
                _eph = getattr(app, '_empty_placeholder', None)
                if _eph:
                    try: _eph.destroy()
                    except: pass
                _eph = tk.Frame(app.cards_frame, bg='#0f1b2a')
                tk.Label(_eph, text='Henuz SteamDB verisi yok', fg='#7c6fff',
                        bg='#0f1b2a', font=('Segoe UI', 14)).pack(pady=20)
                tk.Label(_eph, text='Yuklemek icin \U0001f504 Refresh butonuna basin', fg='#8fb8da',
                        bg='#0f1b2a', font=('Segoe UI', 10)).pack(pady=(0, 20))
                _eph.pack(fill=tk.BOTH, expand=True)
                app._empty_placeholder = _eph
        except Exception as ex:
            import traceback
            traceback.print_exc()

    # Style existing scrollbars
    def _style_scrollbars(widget):
        try:
            for child in widget.winfo_children():
                try:
                    if child.winfo_class() == 'Scrollbar':
                        child.configure(bg='#1a1a38', troughcolor='#0a0a16',
                                        activebackground='#2a2a5a', relief=tk.FLAT,
                                        width=14, borderwidth=2,
                                        highlightbackground='#1a1a38')
                        try: child.configure(elementborderwidth=1)
                        except: pass
                except: pass
                _style_scrollbars(child)
        except: pass
    root.after(100, lambda: (_style_scrollbars(root), None))
    root.after(800, _init_steamdb_browser)

    # ---- Auto update check (console output + popup + self-replace) ----
    def _check_auto_update():
        import threading as _thr
        def _show_popup(latest, is_tr):
            lang = app.settings.get('language', 'tr')
            is_tr = lang == 'tr'
            _skip_file = Path(os.environ.get('APPDATA', str(Path.home()))) / "SteamToolsLua" / ".skip_update"
            _popup = tk.Toplevel(app.root)
            _popup.title('Guncelleme' if is_tr else 'Update')
            _popup.geometry('400x250')
            _popup.configure(bg='#0d1724')
            _popup.transient(app.root)
            tk.Label(_popup, text=('Yeni Surum Mevcut!' if is_tr else 'New Version Available!'),
                    fg='#48bb78', bg='#0d1724', font=('Bahnschrift SemiBold', 16)).pack(pady=(20, 8))
            tk.Label(_popup, text=f'v{VERSION} -> v{latest}', fg='#dce7f4', bg='#0d1724',
                    font=('Segoe UI', 12)).pack(pady=(0, 6))
            _status_lbl = tk.Label(_popup, text='', fg='#97afc6', bg='#0d1724', font=('Segoe UI', 9))
            _status_lbl.pack(pady=(0, 6))
            _skip_var = tk.BooleanVar(value=False)
            tk.Checkbutton(_popup, text='Bir daha gosterme' if is_tr else "Don't show again",
                          variable=_skip_var, bg='#0d1724', activebackground='#0d1724',
                          selectcolor='#244363', fg='#97afc6', font=('Segoe UI', 9)).pack(pady=(0, 6))
            _btnf = tk.Frame(_popup, bg='#0d1724')
            _btnf.pack()
            def _do_update():
                if _skip_var.get():
                    app.settings['skip_update_notification'] = True
                    g['save_settings'](app.settings)
                    try: _skip_file.write_text('1')
                    except: pass
                _popup.destroy()
                try: app.root.attributes('-toolwindow', False)
                except: pass
                _download_and_replace(latest, is_tr)
            def _skip_dlg():
                if _skip_var.get():
                    app.settings['skip_update_notification'] = True
                    g['save_settings'](app.settings)
                    try: _skip_file.write_text('1')
                    except: pass
                _popup.destroy()
                try: app.root.attributes('-toolwindow', False)
                except: pass
            _popup.protocol('WM_DELETE_WINDOW', _skip_dlg)
            AB = g.get('AnimatedButton', AnimatedButton)
            AB(_btnf, 'Guncelle' if is_tr else 'Update', _do_update, 100, 32,
               '#244363', '#315f8e', '#66c0f4', '#ffffff',
               ('Segoe UI Semibold', 10)).pack(side=tk.LEFT, padx=4)
            AB(_btnf, 'Daha Sonra' if is_tr else 'Later', _skip_dlg, 100, 32,
               '#1f3348', '#2b4b68', '#66c0f4', '#ffffff',
               ('Segoe UI Semibold', 10)).pack(side=tk.LEFT, padx=4)
        def _task():
            try:
                import requests as _req
                lang = app.settings.get('language', 'tr')
                is_tr = lang == 'tr'
                if app.settings.get('skip_update_notification', False):
                    return
                _skip_file = Path(os.environ.get('APPDATA', str(Path.home()))) / "SteamToolsLua" / ".skip_update"
                if _skip_file.exists():
                    return
                print('[Update] Sürüm kontrol ediliyor...' if is_tr else '[Update] Checking version...')
                app.log('[Update] Sürüm kontrol ediliyor...')
                r = _req.get(UPDATE_URL, timeout=10)
                if r.status_code != 200:
                    print(f'[Update] Sürüm kontrolü başarısız (HTTP {r.status_code})')
                    app.log(f'[Update] Sürüm hatasi: {r.status_code}')
                    return
                latest = r.text.strip()
                current = VERSION
                if not latest or latest == current:
                    print(f'[Update] Zaten guncel (v{current})')
                    return
                def _parse(v):
                    parts = v.split('.')
                    return tuple(int(x) if x.isdigit() else 0 for x in parts) + (0,)*4
                if _parse(latest) <= _parse(current):
                    print(f'[Update] Zaten guncel (v{current})')
                    return
                print(f'[Update] Yeni surum: v{current} -> v{latest}')
                app.log(f'[Update] Yeni surum bulundu: v{latest}')
                app.root.after(0, lambda: _show_popup(latest, is_tr))
            except:
                import traceback; traceback.print_exc()
        def _download_and_replace(latest, is_tr):
            def _dl_task():
                try:
                    import requests as _req
                    dl_url = f'{DOWNLOAD_BASE}/v{latest}/SteamToolsLua.exe'
                    print(f'[Update] Indiriliyor: {dl_url}')
                    app.log(f'[Update] {latest} indiriliyor...')
                    me = Path(sys.argv[0] if getattr(sys, 'frozen', False) else __file__).resolve()
                    out_path = me.parent / f'SteamToolsLua_v{latest}.exe'
                    d = _req.get(dl_url, timeout=120, stream=True)
                    if d.status_code != 200:
                        print(f'[Update] HTTP {d.status_code}')
                        app.log(f'[Update] HTTP hatasi: {d.status_code}')
                        _messagebox.showerror('Update', f'Indirme basarisiz (HTTP {d.status_code})')
                        return
                    total = int(d.headers.get('Content-Length', 0))
                    downloaded = 0
                    with open(str(out_path), 'wb') as f:
                        for chunk in d.iter_content(8192):
                            if chunk:
                                f.write(chunk)
                                downloaded += len(chunk)
                                if total and downloaded % (1024*1024) < 8192:
                                    pct = downloaded * 100 // total
                                    print(f'[Update] Indirme: %{pct} ({downloaded//1024//1024}MB/{total//1024//1024}MB)')
                                    app.root.after(0, lambda p=pct: app._set_indicator(f'Guncelleme: %{p}', 'working'))
                    print(f'[Update] Indi: {out_path} ({downloaded//1024//1024}MB)')
                    app.log(f'[Update] v{latest} indirildi, baslatiliyor...')
                    try:
                        _info = {"old_name": me.name, "old_path": str(me.parent), "updated_to": latest}
                        _info_file = me.parent / '.update_info.txt'
                        _info_file.write_text(json.dumps(_info), encoding='utf-8')
                    except: pass
                    import subprocess as _sp
                    _sp.Popen([str(out_path)], close_fds=True)
                    app.root.after(500, lambda: os._exit(0))
                except:
                    import traceback; traceback.print_exc()
                    _messagebox.showerror('Update', 'Guncelleme basarisiz.')
            _thr.Thread(target=_dl_task, daemon=True).start()
        _thr.Thread(target=_task, daemon=True).start()
    root.after(1500, _check_auto_update)

    # ---- Single first-run flow: setup wizard → nickname ----
    def _first_run_flow(app):
        _flag = _data_dir / ".setup_done"
        if _flag.exists():
            if _ROOT:
                try: _ROOT.after(8000, _startup_nickname)
                except: pass
            return
        app.open_settings_window()
        def _finish_setup():
            try: _flag.write_text("1", encoding='utf-8')
            except: pass
            _win2 = getattr(app, 'settings_window', None)
            if _win2 and _win2.winfo_exists():
                _win2.destroy()
            if _ROOT:
                try: _ROOT.after(500, _startup_nickname)
                except: pass
        _win = getattr(app, 'settings_window', None)
        if _win and _win.winfo_exists():
            _old_close = _win.protocol('WM_DELETE_WINDOW', None)
            _win.protocol('WM_DELETE_WINDOW', lambda: (_finish_setup(), _win.destroy()))
            is_tr = app.settings.get('language', 'tr') == 'tr'
            tk.Button(_win, text='Kurulumu Tamamla / Finish Setup' if is_tr else 'Finish Setup',
                bg='#244363', fg='#ffffff', relief=tk.FLAT, padx=12, pady=6,
                font=('Segoe UI', 10, 'bold'), cursor='hand2',
                command=lambda: (_finish_setup(), _win.destroy())).pack(side=tk.BOTTOM, pady=10)
    root.after(500, lambda: _first_run_flow(app))



    # ---- Inject OF Button Flow ----
    def _inject_of_flow(app):
        _tk_fd = __import__('tkinter.filedialog')
        _exe_path = _tk_fd.askopenfilename(
            title=_tr(app, 'inject_of.exe_label'),
            filetypes=[('Executable files', '*.exe'), ('All files', '*.*')]
        )
        if not _exe_path:
            return
        _default_dir = str(Path("C:\\Program Files (x86)\\Steam\\steamapps\\common"))
        _dest_dir = _tk_fd.askdirectory(
            title=_tr(app, 'inject_of.dir_label'),
            initialdir=_default_dir
        )
        if not _dest_dir:
            return
        def _task():
            try:
                app._set_indicator('Inject OF: basliyor...', 'working')
                _exe_name = Path(_exe_path).name
                _dest_path = Path(_dest_dir) / _exe_name
                try:
                    _shutil.copy2(_exe_path, str(_dest_path))
                    app.log(f"[Inject OF] {_exe_name} -> {_dest_dir}")
                except Exception as _cp_err:
                    app._set_indicator(_tr(app, 'inject_of.err').format(err=str(_cp_err)), 'offline')
                    return
                _stplug_dir = Path("C:\\Program Files (x86)\\Steam\\config\\stplug-in")
                _stplug_dir.mkdir(parents=True, exist_ok=True)
                _lua_name = Path(_exe_path).stem + ".lua"
                _lua_src = Path(_exe_path).parent / _lua_name
                if _lua_src.exists():
                    try:
                        _shutil.copy2(str(_lua_src), str(_stplug_dir / _lua_name))
                        app.log(f"[Inject OF] Lua: {_lua_name} -> stplug-in/")
                    except Exception as _lua_err:
                        app.log(f"[Inject OF] Lua kopyalama hatasi: {_lua_err}")
                app._set_indicator(_tr(app, 'inject_of.done'), 'online')
                app.root.after(0, lambda: _messagebox.showinfo(
                    _tr(app, 'inject_of.done'),
                    f"{_exe_name} -> {_dest_dir}"
                ))
            except Exception as _ex:
                app._set_indicator(_tr(app, 'inject_of.err').format(err=str(_ex)), 'offline')
        __import__('threading').Thread(target=_task, daemon=True).start()
    SteamApp._inject_of_flow = _inject_of_flow

    # ---- Updater: extract + schedule + patch settings ----
    def _ensure_updater():
        _ad = Path(os.environ.get('APPDATA', str(Path.home()))) / 'SteamToolsLua'
        _ad.mkdir(parents=True, exist_ok=True)
        _tgt = _ad / 'STL_Update.exe'
        if not _tgt.exists():
            _src = None
            if getattr(sys, 'frozen', False):
                _mp = getattr(sys, '_MEIPASS', None)
                if _mp:
                    _c = Path(_mp) / 'STL_Update.exe'
                    if _c.exists(): _src = _c
            if not _src:
                _c = Path(__file__).parent / 'STL_Update.exe'
                if _c.exists(): _src = _c
            if _src:
                try: shutil.copy2(str(_src), str(_tgt))
                except: pass
        return _tgt if _tgt.exists() else None

    _updater_exe = _ensure_updater()
    _exe_path = sys.executable if getattr(sys, 'frozen', False) else __file__

    def _launch_updater():
        try:
            if _updater_exe:
                subprocess.Popen(
                    [str(_updater_exe), '--current', VERSION, '--exe', _exe_path],
                    creationflags=subprocess.CREATE_NO_WINDOW
                )
        except:
            pass

    # Auto check after 15s
    _ru = getattr(g.get('app'), 'root', None) if g.get('app') else None
    if _ru:
        try: _ru.after(15000, _launch_updater)
        except: pass

